const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const operation = trigger.operation || 'save';
const userId = trigger.user_id || '';
const userFilter = userId ? '&user_id=eq.' + encodeURIComponent(userId) : '';

let result = '';

if (operation === 'save') {
  const body = {
    topic: trigger.topic,
    genre_slug: trigger.genre_slug || null,
    content: trigger.content,
    status: trigger.status || 'draft',
    user_id: userId
  };
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/research_reports_v2',
    headers: { ...headers, 'Prefer': 'return=representation' },
    body
  });
  result = JSON.stringify(Array.isArray(resp) ? resp[0] : resp);
} else if (operation === 'get') {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/research_reports_v2?id=eq.' + trigger.report_id + '&limit=1' + userFilter,
    headers
  });
  result = JSON.stringify(Array.isArray(resp) && resp.length > 0 ? resp[0] : { error: 'Report not found' });
} else if (operation === 'list') {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/research_reports_v2?order=updated_at.desc&limit=20&select=id,topic,genre_slug,status,created_at,updated_at' + userFilter,
    headers
  });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No research reports found.';
  } else {
    result = 'Found ' + items.length + ' report(s):\n' + items.map((item, i) =>
      (i + 1) + '. ' + item.topic + ' (' + (item.genre_slug || 'no genre') + ', ' + item.status + ') [ID: ' + item.id + ']'
    ).join('\n');
  }
} else if (operation === 'update') {
  const body = {};
  if (trigger.content) body.content = trigger.content;
  if (trigger.topic) body.topic = trigger.topic;
  if (trigger.status) body.status = trigger.status;
  body.updated_at = new Date().toISOString();
  const resp = await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/research_reports_v2?id=eq.' + trigger.report_id + userFilter,
    headers: { ...headers, 'Prefer': 'return=representation' },
    body
  });
  result = JSON.stringify(Array.isArray(resp) ? resp[0] : resp);
} else {
  result = 'Unknown operation: ' + operation + '. Valid: save, get, list, update';
}

return [{ json: { result } }];

